function createWeakCache() {
  const cache = new Map();
  return {
    set(key, value) {
      cache.set(key, new WeakRef(value));
    },
    get(key) {
      const ref = cache.get(key);
      if (!ref) return undefined;
      const value = ref.deref();
      if (!value) { cache.delete(key); return undefined; }
      return value;
    }
  };
}

