function* tokenize(code) {
  const patterns = [
    ['NUMBER', /\d+/y],
    ['OP', /[+\-*/]/y],
    ['SPACE', /\s+/y],
    ['ID', /[a-zA-Z_]\w*/y]
  ];
  let pos = 0;
  while (pos < code.length) {
    for (const [type, regex] of patterns) {
      regex.lastIndex = pos;
      const match = regex.exec(code);
      if (match) {
        pos = regex.lastIndex;
        if (type !== 'SPACE') yield { type, value: match[0] };
        break;
      }
    }
  }
}
